 public class OrderPricingService extends OrderPricingServiceSuper {

     public String summarize(List<Double> items, String label) {
         StringBuilder sb = new StringBuilder();
         double total = 0;
         int i = 0;
         for (Double x : items) {
             sb.append("item#").append(i).append("=").append(String.format("%.2f", x)).append("\n");
             total += x;
             i++;
         }
         sb.append(label).append("=").append(String.format("%.2f", total));
         return sb.toString();
     }
 }

